class Solution:
    def findAnagrams(self, s, p):
        from collections import Counter
        if len(p) > len(s):
            return []
        pc = Counter(p)
        result = []
        for i in range(len(s) - len(p) + 1):
            if Counter(s[i:i+len(p)]) == pc:
                result.append(i)
        return result

