class Solution:
    def findAnagrams(self, s, p):
        from collections import Counter
        ns, np = len(s), len(p)
        if np > ns:
            return []
        pc = Counter(p)
        wc = Counter(s[:np])
        result = []
        if wc == pc:
            result.append(0)
        for i in range(np, ns):
            wc[s[i]] += 1
            left = s[i - np]
            wc[left] -= 1
            if wc[left] == 0:
                del wc[left]
            if wc == pc:
                result.append(i - np + 1)
        return result

