var findAnagrams = function(s, p) {
    const ns = s.length, np = p.length;
    if (np > ns) return [];
    const pc = new Array(26).fill(0);
    const wc = new Array(26).fill(0);
    const a = 'a'.charCodeAt(0);
    for (let i = 0; i < np; i++) {
        pc[p.charCodeAt(i)-a]++;
        wc[s.charCodeAt(i)-a]++;
    }
    let diff = 0;
    for (let i = 0; i < 26; i++) if (pc[i] !== wc[i]) diff++;
    const result = [];
    if (diff === 0) result.push(0);
    for (let i = np; i < ns; i++) {
        const add = s.charCodeAt(i)-a;
        const rem = s.charCodeAt(i-np)-a;
        // add new char
        if (wc[add] === pc[add]) diff++;
        wc[add]++;
        if (wc[add] === pc[add]) diff--;
        // remove old char
        if (wc[rem] === pc[rem]) diff++;
        wc[rem]--;
        if (wc[rem] === pc[rem]) diff--;
        if (diff === 0) result.push(i - np + 1);
    }
    return result;
};
